INSERT INTO GOI_TIEM_VC (MaGoi, TenGoi, ThoiHan, GiamGia, SoMuiTuongUng, GhiChu) VALUES (N'GOI001', N'Gói Tiêm Chủng Cơ Bản', 6, 0.02, 2, N'Lựa chọn tối ưu cho khởi đầu bảo vệ, áp dụng cho 2 mũi tiêm phổ biến nhất.');
