INSERT INTO GOI_TIEM_VC (MaGoi, TenGoi, ThoiHan, GiamGia, SoMuiTuongUng, GhiChu) VALUES (N'GOI004', N'Gói Kim Cương Bảo Hộ Dài Lâu', 18, 0.20, 5, N'Tiết kiệm nhất! Giảm 20% chi phí cho 5 mũi vaccine, bảo vệ liên tục trong 18 tháng.');